ce/empty-cart-block -->\n<div class=\"wp-block-woocommerce-empty-cart-block\"><!-- wp:heading {\"textAlign\":\"center\",\"className\":\"with-empty-cart-icon wc-block-cart__empty-cart__title\"} -->\n<h2 class=\"wp-block-heading has-text-align-center with-empty-cart-icon wc-block-cart__empty-cart__title\">Your cart is currently empty!</h2>\n<!-- /wp:heading -->\n\n<!-- wp:separator {\"className\":\"is-style-dots\"} -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity is-style-dots\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"textAlign\":\"center\"} -->\n<h2 class=\"wp-block-heading has-text-align-center\">New in store</h2>\n<!-- /wp:heading -->\n\n<!-- wp:woocommerce/product-new {\"columns\":4,\"rows\":1} /--></div>\n<!-- /wp:woocommerce/empty-cart-block --></div>\n<!-- /wp:woocommerce/cart -->','Cart','','publish','closed','closed','','cart','','','2026-03-05 22:48:38','2026-03-05 22:48:38','',0,'http://localhost:8080/?page_id=9',0,'page','',0),(10,1,'2026-03-05 21:22:33','2026-03-05 21:22:33','<!-- wp:woocommerce/checkout -->\n<div class=\"wp-block-woocommerce-checkout alignwide wc-block-checkout is-loading\"><!-- wp:woocommerce/checkout-fields-block -->\n<div class=\"wp-block-woocommerce-checkout-fields-block\"><!-- wp:woocommerce/checkout-express-payment-block -->\n<div class=\"wp-block-woocommerce-checkout-express-payment-block\"></div>\n<!-- /wp:woocommerce/checkout-express-payment-block -->\n\n<!-- wp:woocommerce/checkout-contact-information-block -->\n<div class=\"wp-block-woocommerce-checkout-contact-information-block\"></div>\n<!-- /wp:woocommerce/checkout-contact-information-block -->\n\n<!-- wp:woocommerce/checkout-shipping-method-block -->\n<div class=\"wp-block-woocommerce-checkout-shipping-method-block\"></div>\n<!-- /wp:woocommerce/checkout-shipping-method-block -->\n\n<!-- wp:woocommerce/checkout-pickup-options-block -->\n<div class=\"wp-block-woocommerce-checkout-pickup-options-block\"></div>\n<!-- /wp:woocommerce/checkout-pickup-options-block -->\n\n<!-- wp:woocommerce/checkout-shipping-address-block -->\n<div class=\"wp-block-woocommerce-checkout-shipping-address-block\"></div>\n<!-- /wp:woocommerce/checkout-shipping-address-block -->\n\n<!-- wp:woocommerce/checkout-billing-address-block -->\n<div class=\"wp-block-woocommerce-checkout-billing-address-block\"></div>\n<!-- /wp:woocommerce/checkout-billing-address-block -->\n\n<!-- wp:woocommerce/checkout-shipping-methods-block -->\n<div class=\"wp-block-woocommerce-checkout-shipping-methods-block\"></div>\n<!-- /wp:woocommerce/checkout-shipping-methods-block -->\n\n<!-- wp:woocommerce/checkout-payment-block -->\n<div class=\"wp-block-woocommerce-checkout-payment-block\"></div>\n<!-- /wp:woocommerce/checkout-payment-block -->\n\n<!-- wp:woocommerce/checkout-additional-information-block -->\n<div class=\"wp-block-woocommerce-checkout-additional-information-block\"></div>\n<!-- /wp:woocommerce/checkout-additional-information-block -->\n\n<!-- wp:woocommerce/checkout-order-note-block -->\n<div class=\"wp-block-woocommerce-checkout-order-note-block\"></div>\n<!-- /wp:woocommerce/checkout-order-note-block -->\n\n<!-- wp:woocommerce/checkout-terms-block -->\n<div class=\"wp-block-woocommerce-checkout-terms-block\"></div>\n<!-- /wp:woocommerce/checkout-terms-block -->\n\n<!-- wp:woocommerce/checkout-actions-block -->\n<div class=\"wp-block-woocommerce-checkout-actions-block\"></div>\n<!-- /wp:woocommerce/checkout-actions-block --></div>\n<!-- /wp:woocommerce/checkout-fields-block -->\n\n<!-- wp:woocommerce/checkout-totals-block -->\n<div class=\"wp-block-woocommerce-checkout-totals-block\"><!-- wp:woocommerce/checkout-order-summary-block -->\n<div class=\"wp-block-woocommerce-checkout-order-summary-block\"><!-- wp:woocommerce/checkout-order-summary-cart-items-block -->\n<div class=\"wp-block-woocommerce-checkout-order-summary-cart-items-block\"></div>\n<!-- /wp:woocommerce/checkout-order-summary-cart-items-block -->\n\n<!-- wp:woocommerce/checkout-order-summary-coupon-form-block -->\n<div class=\"wp-block-woocommerce-checkout-order-summary-coupon-form-block\"></div>\n<!-- /wp:woocommerce/checkout-order-summary-coupon-form-block -->\n\n<!-- wp:woocommerce/checkout-order-summary-subtotal-block -->\n<div class=\"wp-block-woocommerce-checkout-order-summary-subtotal-block\"></div>\n<!-- /wp:woocommerce/checkout-order-summary-subtotal-block -->\n\n<!-- wp:woocommerce/checkout-order-summary-fee-block -->\n<div class=\"wp-block-woocommerce-checkout-order-summary-fee-block\"></div>\n<!-- /wp:woocommerce/checkout-order-summary-fee-block -->\n\n<!-- wp:woocommerce/checkout-order-summary-discount-block -->\n<div class=\"wp-block-woocommerce-checkout-order-summary-discount-block\"></div>\n<!-- /wp:woocommerce/checkout-order-summary-discount-block -->\n\n<!-- wp:woocommerce/checkout-order-summary-shipping-block -->\n<div class=\"wp-block-woocommerce-checkout-order-summary-shipping-block\"></div>\n<!-- /wp:woocommerce/checkout-order-summary-shipping-block -->\n\n<!-- wp:woocommerce/checkout-order-summary-taxes-block -->\n<div class=\"wp-block-woocommerce-checkout-order-summary-taxes-block\"></div>\n<!-- /wp:woocommerce/checkout-order-summary-taxes-block --></div>\n<!-- /wp:woocommerce/checkout-order-summary-block --></div>\n<!-- /wp:woocommerce/checkout-totals-block --></div>\n<!-- /wp:woocommerce/checkout -->','Checkout','','publish','closed','closed','','checkout','','','2026-03-05 21:22:33','2026-03-05 21:22:33','',0,'http://localhost:8080/?page_id=10',0,'page','',0),(11,1,'2026-03-05 21:22:33','2026-03-05 21:22:33','<!-- wp:shortcode -->[woocommerce_my_account]<!-- /wp:shortcode -->','My account','','publish','closed','closed','','my-account','','','2026-03-05 21:22:33','2026-03-05 21:22:33','',0,'http://localhost:8080/?page_id=11',0,'page','',0),(12,1,'2026-03-05 21:41:47','2026-03-05 21:41:47','<!-- wp:paragraph -->\n<p><b>This is a sample page.</b></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Overview</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Our refund and returns policy lasts 30 days. If 30 days have passed since your purchase, we can’t offer you a full refund or exchange.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>To be eligible for a return, your item must be unused and in the same condition that you received it. It must also be in the original packaging.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Several types of goods are exempt from being returned. Perishable goods such as food, flowers, newspapers or magazines cannot be returned. We also do not accept products that are intimate or sanitary goods, hazardous materials, or flammable liquids or gases.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Additional non-returnable items:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul>\n<li>Gift cards</li>\n<li>Downloadable software products</li>\n<li>Some health and personal care items</li>\n</ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>To complete your return, we require a receipt or proof of purchase.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Please do not send your purchase back to the manufacturer.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>There are certain situations where only partial refunds are granted:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul>\n<li>Book with obvious signs of use</li>\n<li>CD, DVD, VHS tape, software, video game, cassette tape, or vinyl record that has been opened.</li>\n<li>Any item not in its original condition, is damaged or missing parts for reasons not due to our error.</li>\n<li>Any item that is returned more than 30 days after delivery</li>\n</ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Refunds</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Once your return is received and inspected, we will send you an email to notify you that we have received your returned item. We will also notify you of the approval or rejection of your refund.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If you are approved, then your refund will be processed, and a credit will automatically be applied to your credit card or original method of payment, within a certain amount of days.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Late or missing refunds</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you haven’t received a refund yet, first check your bank account again.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Then contact your credit card company, it may take some time before your refund is officially posted.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Next contact your bank. There is often some processing time before a refund is posted.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If you’ve done all of this and you still have not received your refund yet, please contact us at {email address}.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Sale items</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Only regular priced items may be refunded. Sale items cannot be refunded.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Exchanges</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We only replace items if they are defective or damaged. If you need to exchange it for the same item, send us an email at {email address} and send your item to: {physical address}.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Gifts</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If the item was marked as a gift when purchased and shipped directly to you, you’ll receive a gift credit for the value of your return. Once the returned item is received, a gift certificate will be mailed to you.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If the item wasn’t marked as a gift when purchased, or the gift giver had the order shipped to themselves to give to you later, we will send a refund to the gift giver and they will find out about your return.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Shipping returns</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>To return your product, you should mail your product to: {physical address}.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>You will be responsible for paying for your own shipping costs for returning your item. Shipping costs are non-refundable. If you receive a refund, the cost of return shipping will be deducted from your refund.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Depending on where you live, the time it may take for your exchanged product to reach you may vary.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If you are returning more expensive items, you may consider using a trackable shipping service or purchasing shipping insurance. We don’t guarantee that we will receive your returned item.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Need help?</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Contact us at {email} for questions related to refunds and returns.</p>\n<!-- /wp:paragraph -->','Refund and Returns Policy','','publish','closed','closed','','refund_returns','','','2026-03-05 21:41:47','2026-03-05 21:41:47','',0,'http://localhost:8080/?page_id=12',0,'page','',0),(17,1,'2026-03-05 21:22:59','2026-03-05 21:22:59','','Order &ndash; March 5, 2026 @ 09:22 PM','','wc-checkout-draft','open','closed','wc_order_keitnG8l6A8td','order-mar-05-2026-0922-pm','','','2026-03-05 21:22:59','2026-03-05 21:22:59','',0,'http://localhost:8080/?post_type=shop_order&p=17',0,'shop_order','',0),(18,0,'2026-03-05 21:40:02','2026-03-05 21:40:02','<div class=\"twl-page-section\">\n    <div class=\"twl-split\">\n        <div>\n            <h2 class=\"twl-section-heading\">Our Story</h2>\n            <div class=\"twl-prose\">\n                <p>The Watch Locator was founded with a singular vision: to connect discerning collectors with the world\'s most exceptional timepieces. What began as a passion for horology has grown into one of the UK\'s most trusted names in luxury watch sourcing and authentication.</p>\n                <p>With over two decades of experience in the luxury watch market, our team of certified horologists and watch specialists has built an unrivalled network of trusted dealers, collectors, and auction houses across the globe. We leverage these relationships to source timepieces that meet our exacting standards of quality and authenticity.</p>\n                <p>Every watch that passes through our hands undergoes a rigorous multi-point inspection process, ensuring that each piece meets the highest standards before reaching its new owner. Our commitment to transparency and integrity has earned us the trust of collectors worldwide.</p>\n            </div>\n        </div>\n        <div class=\"twl-split-image\">\n            <img src=\"/wp-content/uploads/2026/03/about-watch.jpg\" alt=\"The Watch Locator — luxury watch authentication and inspection\" />\n        </div>\n    </div>\n</div>\n\n<div class=\"twl-page-section-gray\">\n    <h2 class=\"twl-section-heading twl-section-heading-centered\">Our Expertise</h2>\n    <div class=\"twl-features\">\n        <div class=\"twl-feature\">\n            <div class=\"twl-feature-icon\">\n                <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\" stroke-width=\"1.5\" stroke=\"currentColor\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M12 6v6h4.5m4.5 0a9 9 0 1 1-18 0 9 9 0 0 1 18 0Z\"/></svg>\n            </div>\n            <h3>20+ Years Experience</h3>\n            <p>Two decades of expertise in sourcing, authenticating, and trading luxury timepieces from the world\'s most prestigious manufacturers.</p>\n        </div>\n        <div class=\"twl-feature\">\n            <div class=\"twl-feature-icon\">\n                <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\" stroke-width=\"1.5\" stroke=\"currentColor\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M9 12.75 11.25 15 15 9.75m-3-7.036A11.959 11.959 0 0 1 3.598 6 11.99 11.99 0 0 0 3 9.749c0 5.592 3.824 10.29 9 11.623 5.176-1.332 9-6.03 9-11.622 0-1.31-.21-2.571-.598-3.751h-.152c-3.196 0-6.1-1.248-8.25-3.285Z\"/></svg>\n            </div>\n            <h3>Certified Horologists</h3>\n            <p>Our team holds certifications from leading horological institutions, ensuring every assessment is conducted to the highest professional standards.</p>\n        </div>\n        <div class=\"twl-feature\">\n            <div class=\"twl-feature-icon\">\n                <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\" stroke-width=\"1.5\" stroke=\"currentColor\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"m21 21-5.197-5.197m0 0A7.5 7.5 0 1 0 5.196 5.196a7.5 7.5 0 0 0 10.607 10.607Z\"/></svg>\n            </div>\n            <h3>Thorough Authentication</h3>\n            <p>Every timepiece undergoes a comprehensive multi-point inspection including movement analysis, case verification, and provenance review.</p>\n        </div>\n    </div>\n</div>\n\n<div class=\"twl-image-banner\">\n    <img src=\"/wp-content/uploads/2026/03/hero-watch.jpg\" alt=\"The Watch Locator showroom — luxury watches on display\" />\n</div>\n\n<div class=\"twl-page-section\">\n    <h2 class=\"twl-section-heading twl-section-heading-centered\">Why Choose Us</h2>\n    <div class=\"twl-info-grid\">\n        <div class=\"twl-info-card\">\n            <div class=\"twl-info-card-icon\">\n                <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\" stroke-width=\"1.5\" stroke=\"currentColor\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M9 12.75 11.25 15 15 9.75M21 12c0 1.268-.63 2.39-1.593 3.068a3.745 3.745 0 0 1-1.043 3.296 3.745 3.745 0 0 1-3.296 1.043A3.745 3.745 0 0 1 12 21c-1.268 0-2.39-.63-3.068-1.593a3.746 3.746 0 0 1-3.296-1.043 3.745 3.745 0 0 1-1.043-3.296A3.745 3.745 0 0 1 3 12c0-1.268.63-2.39 1.593-3.068a3.745 3.745 0 0 1 1.043-3.296 3.746 3.746 0 0 1 3.296-1.043A3.746 3.746 0 0 1 12 3c1.268 0 2.39.63 3.068 1.593a3.746 3.746 0 0 1 3.296 1.043 3.746 3.746 0 0 1 1.043 3.296A3.745 3.745 0 0 1 21 12Z\"/></svg>\n            </div>\n            <h3>Authentication Guarantee</h3>\n            <p>Every watch comes with our certificate of authenticity, backed by our team of certified horologists and industry-leading inspection process.</p>\n        </div>\n        <div class=\"twl-info-card\">\n            <div class=\"twl-info-card-icon\">\n                <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\" stroke-width=\"1.5\" stroke=\"currentColor\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M2.25 18.75a60.07 60.07 0 0 1 15.797 2.101c.727.198 1.453-.342 1.453-1.096V18.75M3.75 4.5v.75A.75.75 0 0 1 3 6h-.75m0 0v-.375c0-.621.504-1.125 1.125-1.125H20.25M2.25 6v9m18-10.5v.75c0 .414.336.75.75.75h.75m-1.5-1.5h.375c.621 0 1.125.504 1.125 1.125v9.75c0 .621-.504 1.125-1.125 1.125h-.375m1.5-1.5H21a.75.75 0 0 0-.75.75v.75m0 0H3.75m0 0h-.375a1.125 1.125 0 0 1-1.125-1.125V15m1.5 1.5v-.75A.75.75 0 0 0 3 15h-.75M15 10.5a3 3 0 1 1-6 0 3 3 0 0 1 6 0Zm3 0h.008v.008H18V10.5Zm-12 0h.008v.008H6V10.5Z\"/></svg>\n            </div>\n            <h3>Competitive Pricing</h3>\n            <p>Our extensive network and industry relationships allow us to offer exceptional timepieces at competitive prices, ensuring outstanding value for collectors.</p>\n        </div>\n        <div class=\"twl-info-card\">\n            <div class=\"twl-info-card-icon\">\n                <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\" stroke-width=\"1.5\" stroke=\"currentColor\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M15 19.128a9.38 9.38 0 0 0 2.625.372 9.337 9.337 0 0 0 4.121-.952 4.125 4.125 0 0 0-7.533-2.493M15 19.128v-.003c0-1.113-.285-2.16-.786-3.07M15 19.128v.106A12.318 12.318 0 0 1 8.624 21c-2.331 0-4.512-.645-6.374-1.766l-.001-.109a6.375 6.375 0 0 1 11.964-3.07M12 6.375a3.375 3.375 0 1 1-6.75 0 3.375 3.375 0 0 1 6.75 0Zm8.25 2.25a2.625 2.625 0 1 1-5.25 0 2.625 2.625 0 0 1 5.25 0Z\"/></svg>\n            </div>\n            <h3>Trusted by Collectors</h3>\n            <p>Join thousands of satisfied collectors who have trusted The Watch Locator to source and authenticate their most prized timepieces.</p>\n        </div>\n    </div>\n</div>\n','About','','publish','closed','closed','','about','','','2026-03-06 20:07:24','2026-03-06 20:07:24','',0,'http://localhost:8080/about/',0,'page','',0),(19,0,'2026-03-05 21:40:04','2026-03-05 21:40:04','<div class=\"twl-page-section\">\n    <div class=\"twl-prose-centered\">\n        <p>We would love to hear from you. Whether you are looking to purchase a specific timepiece, sell a watch from your collection, or simply have a question, our team of specialists is here to help.</p>\n    </div>\n    <div class=\"twl-info-grid\">\n        <div class=\"twl-info-card\">\n            <div class=\"twl-info-card-icon\">\n                <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\" stroke-width=\"1.5\" stroke=\"currentColor\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M15 10.5a3 3 0 1 1-6 0 3 3 0 0 1 6 0Z\"/><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M19.5 10.5c0 7.142-7.5 11.25-7.5 11.25S4.5 17.642 4.5 10.5a7.5 7.5 0 1 1 15 0Z\"/></svg>\n            </div>\n            <h3>Visit Our Showroom</h3>\n            <p>47 Hatton Garden<br>London EC1N 8YS<br>United Kingdom</p>\n        </div>\n        <div class=\"twl-info-card\">\n            <div class=\"twl-info-card-icon\">\n                <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\" stroke-width=\"1.5\" stroke=\"currentColor\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M12 6v6h4.5m4.5 0a9 9 0 1 1-18 0 9 9 0 0 1 18 0Z\"/></svg>\n            </div>\n            <h3>Opening Hours</h3>\n            <p>Monday – Friday: 9:00 – 18:00<br>Saturday: 10:00 – 16:00<br>Sunday: By appointment only</p>\n        </div>\n        <div class=\"twl-info-card\">\n            <div class=\"twl-info-card-icon\">\n                <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\" stroke-width=\"1.5\" stroke=\"currentColor\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M21.75 6.75v10.5a2.25 2.25 0 0 1-2.25 2.25h-15a2.25 2.25 0 0 1-2.25-2.25V6.75m19.5 0A2.25 2.25 0 0 0 19.5 4.5h-15a2.25 2.25 0 0 0-2.25 2.25m19.5 0v.243a2.25 2.25 0 0 1-1.07 1.916l-7.5 4.615a2.25 2.25 0 0 1-2.36 0L3.32 8.91a2.25 2.25 0 0 1-1.07-1.916V6.75\"/></svg>\n            </div>\n            <h3>Get in Touch</h3>\n            <p><a href=\"tel:+442071234567\">+44 (0) 207 123 4567</a><br><a href=\"mailto:enquiries@thewatchlocator.com\">enquiries@thewatchlocator.com</a></p>\n        </div>\n    </div>\n</div>\n\n<div class=\"twl-page-section\">\n    <h2 class=\"twl-section-heading twl-section-heading-centered\">Send Us a Message</h2>\n    <div class=\"twl-contact-form\">\n        [twl_contact_form]\n    </div>\n</div>\n\n<div class=\"twl-cta-block\">\n    \n    <p>Experience our collection in a private, relaxed setting. Our specialists will guide you through our finest timepieces.</p>\n    <a href=\"mailto:enquiries@thewatchlocator.com?subject=Private%20Viewing%20Request\" class=\"btn btn-outline-light\">Schedule an Appointment</a>\n</div>\n\n','Contact','','publish','closed','closed','','contact','','','2026-03-06 20:19:56','2026-03-06 20:19:56','',0,'http://localhost:8080/contact/',0,'page','',0),(20,0,'2026-03-05 21:40:05','2026-03-05 21:40:05','<h2>Sell Your Luxury Watch</h2><p>Looking to sell your luxury timepiece? The Watch Locator offers a straightforward, transparent selling process with competitive prices.</p><h2>How It Works</h2><p><strong>1. Get a Quote</strong><br>Contact us with details of your watch — brand, model, year, condition, and any supporting documentation such as box and papers.</p><p><strong>2. Expert Valuation</strong><br>Our certified horologists will assess your timepiece and provide a fair, market-based valuation within 24 hours.</p><p><strong>3. Fast Payment</strong><br>Once you accept our offer, we arrange secure collection and payment is made promptly via bank transfer.</p><h2>What We Buy</h2><p>We purchase watches from all leading luxury brands including Rolex, Patek Philippe, Audemars Piguet, Omega, Cartier, IWC, Jaeger-LeCoultre, Vacheron Constantin, and many more.</p><p>Contact us today for a free, no-obligation quote.</p>','Sell Your Watch','','publish','closed','closed','','sell-your-watch','','','2026-03-05 21:40:05','2026-03-05 21:40:05','',0,'http://localhost:8080/sell-your-watch/',0,'page','',0),(21,0,'2026-03-05 21:40:08','2026-03-05 21:40:08','<div class=\"twl-page-section\">\n    <h2 class=\"twl-section-heading\">Find Your Perfect Timepiece</h2>\n    <div class=\"twl-prose\">\n        <p>Looking for a specific watch? Our locator service leverages a global network of trusted dealers, collectors, and auction houses to source even the most elusive timepieces. Whether it is a discontinued reference, a limited edition, or a specific year and condition — we will find it for you.</p>\n        <p>Simply tell us what you are looking for, and our specialists will conduct a discreet, worldwide search on your behalf. There is no obligation and no upfront cost — you only pay when we find the right watch.</p>\n    </div>\n</div>\n\n<div class=\"twl-page-section\">\n    <h2 class=\"twl-section-heading twl-section-heading-centered\">How It Works</h2>\n    <div class=\"twl-steps\">\n        <div class=\"twl-step\">\n            <div class=\"step-number\">1</div>\n            <h3>Tell Us What You Want</h3>\n            <p>Share the details of the watch you are looking for — brand, model, reference number, year, condition, and any other preferences.</p>\n        </div>\n        <div class=\"twl-step\">\n            <div class=\"step-number\">2</div>\n            <h3>We Search Globally</h3>\n            <p>Our team activates our worldwide network of trusted sources, conducting a thorough and discreet search to locate your timepiece.</p>\n        </div>\n        <div class=\"twl-step\">\n            <div class=\"step-number\">3</div>\n            <h3>Review &amp; Purchase</h3>\n            <p>Once located, we present you with verified options complete with detailed photography, condition reports, and competitive pricing.</p>\n        </div>\n    </div>\n</div>\n\n<div class=\"twl-page-section-gray\">\n    <h2 class=\"twl-section-heading twl-section-heading-centered\">Why Use Our Locator Service</h2>\n    <div class=\"twl-features\">\n        <div class=\"twl-feature\">\n            <div class=\"twl-feature-icon\">\n                <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\" stroke-width=\"1.5\" stroke=\"currentColor\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M2.25 18.75a60.07 60.07 0 0 1 15.797 2.101c.727.198 1.453-.342 1.453-1.096V18.75M3.75 4.5v.75A.75.75 0 0 1 3 6h-.75m0 0v-.375c0-.621.504-1.125 1.125-1.125H20.25M2.25 6v9m18-10.5v.75c0 .414.336.75.75.75h.75m-1.5-1.5h.375c.621 0 1.125.504 1.125 1.125v9.75c0 .621-.504 1.125-1.125 1.125h-.375m1.5-1.5H21a.75.75 0 0 0-.75.75v.75m0 0H3.75m0 0h-.375a1.125 1.125 0 0 1-1.125-1.125V15m1.5 1.5v-.75A.75.75 0 0 0 3 15h-.75M15 10.5a3 3 0 1 1-6 0 3 3 0 0 1 6 0Zm3 0h.008v.008H18V10.5Zm-12 0h.008v.008H6V10.5Z\"/></svg>\n            </div>\n            <h3>No Upfront Fees</h3>\n            <p>Our locator service is completely free to use. You only pay when we find the watch you are looking for and you decide to proceed.</p>\n        </div>\n        <div class=\"twl-feature\">\n            <div class=\"twl-feature-icon\">\n                <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\" stroke-width=\"1.5\" stroke=\"currentColor\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M12 21a9.004 9.004 0 0 0 8.716-6.747M12 21a9.004 9.004 0 0 1-8.716-6.747M12 21c2.485 0 4.5-4.03 4.5-9S14.485 3 12 3m0 18c-2.485 0-4.5-4.03-4.5-9S9.515 3 12 3m0 0a8.997 8.997 0 0 1 7.843 4.582M12 3a8.997 8.997 0 0 0-7.843 4.582m15.686 0A11.953 11.953 0 0 1 12 10.5c-2.998 0-5.74-1.1-7.843-2.918m15.686 0A8.959 8.959 0 0 1 21 12c0 .778-.099 1.533-.284 2.253m0 0A17.919 17.919 0 0 1 12 16.5c-3.162 0-6.133-.815-8.716-2.247m0 0A9.015 9.015 0 0 1 3 12c0-1.605.42-3.113 1.157-4.418\"/></svg>\n            </div>\n            <h3>Global Network</h3>\n            <p>Access our worldwide network of authorised dealers, private collectors, and auction houses spanning over 30 countries.</p>\n        </div>\n        <div class=\"twl-feature\">\n            <div class=\"twl-feature-icon\">\n                <svg xmlns=\"http://www.w3.org/2000/svg\" fill=\"none\" viewBox=\"0 0 24 24\" stroke-width=\"1.5\" stroke=\"currentColor\"><path stroke-linecap=\"round\" stroke-linejoin=\"round\" d=\"M9 12.75 11.25 15 15 9.75m-3-7.036A11.959 11.959 0 0 1 3.598 6 11.99 11.99 0 0 0 3 9.749c0 5.592 3.824 10.29 9 11.623 5.176-1.332 9-6.03 9-11.622 0-1.31-.21-2.571-.598-3.751h-.152c-3.196 0-6.1-1.248-8.25-3.285Z\"/></svg>\n            </div>\n            <h3>Fully Authenticated</h3>\n            <p>Every watch sourced through our locator service undergoes our rigorous authentication process before it reaches you.</p>\n        </div>\n    </div>\n</div>\n\n<div class=\"twl-cta-block\">\n    \n    <p>Tell us which timepiece you are looking for and let our specialists do the rest.</p>\n    <a href=\"/contact/\" class=\"btn btn-outline-light\">Get in Touch</a>\n</div>\n\n','Locate','','publish','closed','closed','','locate','','','2026-03-06 20:19:57','2026-03-06 20:19:57','',0,'http://localhost:8080/locate/',0,'page','',0),(22,0,'2026-03-05 21:40:15','2026-03-05 21:40:15','<h2>Terms and Conditions</h2><p>These terms and conditions govern your use of The Watch Locator website and our services. By using our website or purchasing from us, you agree to these terms.</p><h3>Products and Pricing</h3><p>All prices are displayed in British Pounds (GBP) and include VAT where applicable. We reserve the right to change prices at any time without prior notice.</p><h3>Orders and Payment</h3><p>All orders are subject to availability and acceptance. Payment must be received in full before dispatch. We accept major credit cards, debit cards, and bank transfers.</p><h3>Authenticity Guarantee</h3><p>Every watch sold by The Watch Locator is guaranteed to be 100% authentic. Each timepiece comes with a certificate of authenticity and our comprehensive warranty.</p><h3>Governing Law</h3><p>These terms are governed by the laws of England and Wales.</p>','Terms & Conditions','','publish','closed','closed','','terms-and-conditions','','','2026-03-05 21:40:15','2026-03-05 21:40:15','',0,'http://localhost:8080/terms-and-conditions/',0,'page','',0),(23,0,'2026-03-05 21:40:21','2026-03-05 21:40:21','<h2>Returns Policy</h2><p>At The Watch Locator, we want you to be completely satisfied with your purchase. If for any reason you are not happy, we offer a comprehensive returns policy.</p><h3>14-Day Returns</h3><p>You have 14 days from the date of delivery to return your watch for a full refund, provided it is returned in its original condition with all packaging, documentation, and accessories.</p><h3>How to Return</h3><p>To initiate a return, please contact our team at info@thewatchlocator.com or call +44 20 7123 4567.</p><h3>Condition of Returns</h3><p>Returned watches must be unworn, in the same condition as received, and include all original packaging, papers, tags, and accessories.</p><h3>Refund Processing</h3><p>Refunds are processed within 5 business days of receiving the returned item. The refund will be issued to the original payment method.</p><h3>Exchanges</h3><p>We are happy to exchange your purchase for another timepiece. Contact us to discuss available options.</p>','Returns Policy','','publish','closed','closed','','returns-policy','','','2026-03-05 21:40:21','2026-03-05 21:40:21','',0,'http://localhost:8080/returns-policy/',0,'page','',0),(24,0,'2026-03-05 21:40:26','2026-03-05 21:40:26','<h2>Our Warranty</h2><p>Every watch purchased from The Watch Locator comes with our comprehensive warranty, giving you peace of mind with your investment.</p><h3>24-Month Warranty</h3><p>All watches sold by The Watch Locator carry a 24-month warranty covering mechanical defects and movement issues. This warranty begins from the date of purchase.</p><h3>What Is Covered</h3><p>Our warranty covers manufacturing defects, movement malfunctions, and issues arising from normal use. This includes internal mechanism failures, crown and winding issues, and timekeeping accuracy problems.</p><h3>What Is Not Covered</h3><p>The warranty does not cover damage caused by accidents, misuse, water damage beyond the rated resistance, unauthorised modifications, or normal wear and tear.</p><h3>Making a Claim</h3><p>To make a warranty claim, contact us with your proof of purchase and a description of the issue. Our team will arrange collection and assessment.</p><h3>Extended Warranty</h3><p>We offer extended warranty options for additional peace of mind. Ask our team for details at the time of purchase.</p>','Warranty','','publish','closed','closed','','warranty','','','2026-03-05 21:40:26','2026-03-05 21:40:26','',0,'http://localhost:8080/warranty/',0,'page','',0),(25,0,'2026-03-05 21:40:36','2026-03-05 21:40:36','','Shop','','publish','closed','closed','','shop','','','2026-03-05 21:40:36','2026-03-05 21:40:36','',0,'http://localhost:8080/shop/',0,'nav_menu_item','',0),(26,0,'2026-03-05 21:40:37','2026-03-05 21:40:37','','Sell','','publish','closed','closed','','sell','','','2026-03-05 21:40:37','2026-03-05 21:40:37','',0,'http://localhost:8080/sell/',2,'nav_menu_item','',0),(27,0,'2026-03-05 21:40:37','2026-03-05 21:40:37','','Locate','','publish','closed','closed','','locate','','','2026-03-05 21:40:37','2026-03-05 21:40:37','',0,'http://localhost:8080/locate/',3,'nav_menu_item','',0),(28,0,'2026-03-05 21:40:38','2026-03-05 21:40:38','','About','','publish','closed','closed','','about','','','2026-03-05 21:40:38','2026-03-05 21:40:38','',0,'http://localhost:8080/about/',4,'nav_menu_item','',0),(29,0,'2026-03-05 21:40:38','2026-03-05 21:40:38','','Contact','','publish','closed','closed','','contact','','','2026-03-05 21:40:38','2026-03-05 21:40:38','',0,'http://localhost:8080/contact/',5,'nav_menu_item','',0),(30,0,'2026-03-05 21:40:39','2026-03-05 21:40:39','','Shop','','publish','closed','closed','','shop-2','','','2026-03-05 21:40:39','2026-03-05 21:40:39','',0,'http://localhost:8080/shop-2/',0,'nav_menu_item','',0),(31,0,'2026-03-05 21:40:39','2026-03-05 21:40:39','','About','','publish','closed','closed','','about-2','','','2026-03-05 21:40:39','2026-03-05 21:40:39','',0,'http://localhost:8080/about-2/',2,'nav_menu_item','',0),(32,0,'2026-03-05 21:40:40','2026-03-05 21:40:40','','Contact','','publish','closed','closed','','contact-2','','','2026-03-05 21:40:40','2026-03-05 21:40:40','',0,'http://localhost:8080/contact-2/',3,'nav_menu_item','',0),(33,0,'2026-03-05 21:40:40','2026-03-05 21:40:40','','Sell Your Watch','','publish','closed','closed','','sell-your-watch','','','2026-03-05 21:40:40','2026-03-05 21:40:40','',0,'http://localhost:8080/sell-your-watch/',4,'nav_menu_item','',0),(34,0,'2026-03-05 21:40:41','2026-03-05 21:40:41','','Locate','','publish','closed','closed','','locate-2','','','2026-03-05 21:40:41','2026-03-05 21:40:41','',0,'http://localhost:8080/locate-2/',5,'nav_menu_item','',0),(35,0,'2026-03-05 21:40:58','2026-03-05 21:40:58','','Hero Watch Background','','inherit','open','closed','','hero-watch-background','','','2026-03-05 21:40:58','2026-03-05 21:40:58','',0,'http://localhost:8080/wp-content/uploads/2026/03/hero-watch.jpg',0,'attachment','image/jpeg',0),(36,0,'2026-03-05 21:40:59','2026-03-05 21:40:59','','Rolex Submariner','','inherit','open','closed','','rolex-submariner','','','2026-03-05 21:40:59','2026-03-05 21:40:59','',0,'http://localhost:8080/wp-content/uploads/2026/03/rolex-watch.jpg',0,'attachment','image/jpeg',0),(37,0,'2026-03-05 21:41:00','2026-03-05 21:41:00','','Omega Speedmaster','','inherit','open','closed','','omega-speedmaster','','','2026-03-05 21:41:00','2026-03-05 21:41:00','',0,'http://localhost:8080/wp-content/uploads/2026/03/omega-watch.jpg',0,'attachment','image/jpeg',0),(38,0,'2026-03-05 21:41:00','2026-03-05 21:41:00','','Patek Philippe Nautilus','','inherit','open','closed','','patek-philippe-nautilus','','','2026-03-05 21:41:00','2026-03-05 21:41:00','',0,'http://localhost:8080/wp-content/uploads/2026/03/patek-watch.jpg',0,'attachment','image/jpeg',0),(39,0,'2026-03-05 21:41:01','2026-03-05 21:41:01','','Audemars Piguet Royal Oak','','inherit','open','closed','','audemars-piguet-royal-oak-2','','','2026-03-05 21:41:01','2026-03-05 21:41:01','',0,'http://localhost:8080/wp-content/uploads/2026/03/ap-watch.jpg',0,'attachment','image/jpeg',0),(40,0,'2026-03-05 21:41:02','2026-03-05 21:41:02','','About The Watch Locator','','inherit','open','closed','','about-the-watch-locator','','','2026-03-05 21:41:02','2026-03-05 21:41:02','',0,'http://localhost:8080/wp-content/uploads/2026/03/about-watch.jpg',0,'attachment','image/jpeg',0),(41,0,'2026-03-05 21:41:46','2026-03-05 21:41:46','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Who we are</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Our website address is: http://localhost:8080.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Comments</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>When visitors leave comments on the site we collect the data shown in the comments form, and also the visitor&#8217;s IP address and browser user agent string to help spam detection.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>An anonymised string created from your email address (also called a hash) may be provided to the Gravatar service to see if you are using it. The Gravatar service Privacy Policy is available here: https://automattic.com/privacy/. After approval of your comment, your profile picture is visible to the public in the context of your comment.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Media</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you upload images to the website, you should avoid uploading images with embedded location data (EXIF GPS) included. Visitors to the website can download and extract any location data from images on the website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Cookies</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment on our site you may opt in to saving your name, email address and website in cookies. These are for your convenience so that you do not have to fill in your details again when you leave another comment. These cookies will last for one year.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>If you visit our login page, we will set a temporary cookie to determine if your browser accepts cookies. This cookie contains no personal data and is discarded when you close your browser.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>When you log in, we will also set up several cookies to save your login information and your screen display choices. Login cookies last for two days, and screen options cookies last for a year. If you select &quot;Remember Me&quot;, your login will persist for two weeks. If you log out of your account, the login cookies will be removed.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>If you edit or publish an article, an additional cookie will be saved in your browser. This cookie includes no personal data and simply indicates the post ID of the article you just edited. It expires after 1 day.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Embedded content from other websites</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Articles on this site may include embedded content (e.g. videos, images, articles, etc.). Embedded content from other websites behaves in the exact same way as if the visitor has visited the other website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>These websites may collect data about you, use cookies, embed additional third-party tracking, and monitor your interaction with that embedded content, including tracking your interaction with the embedded content if you have an account and are logged in to that website.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Who we share your data with</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you request a password reset, your IP address will be included in the reset email.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">How long we retain your data</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you leave a comment, the comment and its metadata are retained indefinitely. This is so we can recognise and approve any follow-up comments automatically instead of holding them in a moderation queue.</p>\n<!-- /wp:paragraph -->\n<!-- wp:paragraph -->\n<p>For users that register on our website (if any), we also store the personal information they provide in their user profile. All users can see, edit, or delete their personal information at any time (except they cannot change their username). Website administrators can also see and edit that information.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">What rights you have over your data</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>If you have an account on this site, or have left comments, you can request to receive an exported file of the personal data we hold about you, including any data you have provided to us. You can also request that we erase any personal data we hold about you. This does not include any data we are obliged to keep for administrative, legal, or security purposes.</p>\n<!-- /wp:paragraph -->\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Where your data is sent</h2>\n<!-- /wp:heading -->\n<!-- wp:paragraph -->\n<p><strong class=\"privacy-policy-tutorial\">Suggested text: </strong>Visitor comments may be checked through an automated spam detection service.</p>\n<!-- /wp:paragraph -->\n','Privacy Policy','','inherit','closed','closed','','3-revision-v1','','','2026-03-05 21:41:46','2026-03-05 21:41:46','',3,'http://localhost:8080/?p=41',0,'revision','',0),(42,0,'2026-03-05 21:41:47','2026-03-05 21:41:47','<!-- wp:paragraph -->\n<p><b>This is a sample page.</b></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Overview</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Our refund and returns policy lasts 30 days. If 30 days have passed since your purchase, we can’t offer you a full refund or exchange.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>To be eligible for a return, your item must be unused and in the same condition that you received it. It must also be in the original packaging.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Several types of goods are exempt from being returned. Perishable goods such as food, flowers, newspapers or magazines cannot be returned. We also do not accept products that are intimate or sanitary goods, hazardous materials, or flammable liquids or gases.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Additional non-returnable items:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul>\n<li>Gift cards</li>\n<li>Downloadable software products</li>\n<li>Some health and personal care items</li>\n</ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>To complete your return, we require a receipt or proof of purchase.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Please do not send your purchase back to the manufacturer.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>There are certain situations where only partial refunds are granted:</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul>\n<li>Book with obvious signs of use</li>\n<li>CD, DVD, VHS tape, software, video game, cassette tape, or vinyl record that has been opened.</li>\n<li>Any item not in its original condition, is damaged or missing parts for reasons not due to our error.</li>\n<li>Any item that is returned more than 30 days after delivery</li>\n</ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Refunds</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Once your return is received and inspected, we will send you an email to notify you that we have received your returned item. We will also notify you of the approval or rejection of your refund.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If you are approved, then your refund will be processed, and a credit will automatically be applied to your credit card or original method of payment, within a certain amount of days.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Late or missing refunds</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If you haven’t received a refund yet, first check your bank account again.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Then contact your credit card company, it may take some time before your refund is officially posted.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Next contact your bank. There is often some processing time before a refund is posted.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If you’ve done all of this and you still have not received your refund yet, please contact us at {email address}.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Sale items</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Only regular priced items may be refunded. Sale items cannot be refunded.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Exchanges</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>We only replace items if they are defective or damaged. If you need to exchange it for the same item, send us an email at {email address} and send your item to: {physical address}.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Gifts</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>If the item was marked as a gift when purchased and shipped directly to you, you’ll receive a gift credit for the value of your return. Once the returned item is received, a gift certificate will be mailed to you.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If the item wasn’t marked as a gift when purchased, or the gift giver had the order shipped to themselves to give to you later, we will send a refund to the gift giver and they will find out about your return.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Shipping returns</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>To return your product, you should mail your product to: {physical address}.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>You will be responsible for paying for your own shipping costs for returning your item. Shipping costs are non-refundable. If you receive a refund, the cost of return shipping will be deducted from your refund.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Depending on where you live, the time it may take for your exchanged product to reach you may vary.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>If you are returning more expensive items, you may consider using a trackable shipping service or purchasing shipping insurance. We don’t guarantee that we will receive your returned item.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Need help?</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Contact us at {email} for questions related to refunds and returns.</p>\n<!-- /wp:paragraph -->','Refund and Returns Policy','','inherit','closed','closed','','12-revision-v1','','','2026-03-05 21:41:47','2026-03-05 21:41:47','',12,'http://localhost:8080/?p=42',0,'revision','',0),(43,0,'2026-03-05 21:50:46','2026-03-05 21:50:46','','Hero Video Poster','','inherit','open','closed','','hero-video-poster','','','2026-03-05 21:50:46','2026-03-05 21:50:46','',0,'http://localhost:8080/wp-content/uploads/2026/03/hero-poster.jpg',0,'attachment','image/jpeg',0),(44,1,'2026-03-05 22:08:39','2026-03-05 22:08:39','<strong>Brand:</strong> Omega\n<strong>Model:</strong> test\n<strong>Reference:</strong> \n<strong>Year:</strong> \n<strong>Condition:</strong> Unworn\n<strong>Includes:</strong> Box\n\n<strong>Notes:</strong>\n\n\n<strong>Contact:</strong>\nName: Tyler O\'Sullivan\nEmail: ty.osullivan@gmail.com\nPhone: 07941141135','Omeg